//! MOA Inference Wrapper — fork/race/fold scheduling for NativeLlamaPipeline
//!
//! Orchestrates Glossolalia V2 (MOA + COLTRANE) around the pipeline's forward_one:
//! 1. FORK: k temperature-scaled versions of logits
//! 2. RACE: filter non-finite results
//! 3. FOLD: deficit-weighted merge
//! 4. COLTRANE: apply topological masking
//! 5. INTERFERE: adjust next temperature spread
//!
//! Reference: open-source/aether/src/glossolalia-moa.ts (TypeScript canonical)

use crate::coltrane_constraints::ConstraintFSM;
use crate::glossolalia_moa::{
    create_moa_agents, deficit_weighted_merge, filter_finite_agents, interfere,
    stable_softmax_entropy, InterfereState, MOAAgent, MOAConfig, MOAMergedResult,
};
use crate::model::NativeLlamaPipeline;

pub struct MOAInferencePipeline {
    pipeline: NativeLlamaPipeline,
    config: MOAConfig,
    interfere_state: Option<InterfereState>,
    coltrane_fsm: Option<ConstraintFSM>,
    agents: Vec<MOAAgent>,
}

pub struct MOADecodingResult {
    pub tokens: Vec<u32>,
    pub merged_logits_history: Vec<Vec<f32>>,
    pub violation_history: Vec<f32>,
    pub entropy_history: Vec<f32>,
    pub deficit_history: Vec<usize>,
}

impl MOAInferencePipeline {
    /// Create a new MOA-wrapped inference pipeline.
    pub fn new(pipeline: NativeLlamaPipeline, config: MOAConfig) -> Self {
        let agents = create_moa_agents(&config);
        let interfere_state = if config.interfere {
            Some(InterfereState::new(config.temperature_spread))
        } else {
            None
        };
        let coltrane_fsm = if config.enable_coltrane {
            Some(ConstraintFSM::new())
        } else {
            None
        };

        Self {
            pipeline,
            config,
            interfere_state,
            coltrane_fsm,
            agents,
        }
    }

    /// Decode a sequence with MOA scheduling.
    ///
    /// For each token position:
    /// 1. Call pipeline.forward_one() to get base logits
    /// 2. FORK: Create k temperature-scaled distributions
    /// 3. RACE: Filter non-finite logits
    /// 4. FOLD: Deficit-weighted merge
    /// 5. COLTRANE: Apply topological masking (if enabled)
    /// 6. INTERFERE: Update temperature for next step
    /// 7. Sample token from merged distribution
    pub fn decode_with_moa(
        &mut self,
        prompt_tokens: &[u32],
        max_new_tokens: u32,
    ) -> Result<MOADecodingResult, String> {
        let mut result_tokens = Vec::new();
        let mut merged_logits_history = Vec::new();
        let mut violation_history = Vec::new();
        let mut entropy_history = Vec::new();
        let mut deficit_history = Vec::new();

        let total_steps = prompt_tokens.len() + max_new_tokens as usize;

        for step in 0..total_steps {
            let pos = self.pipeline.pos;
            let token = if step < prompt_tokens.len() {
                prompt_tokens[step] as usize
            } else {
                // Decode next token via MOA
                let merged = self.decode_next_token_moa(pos)?;
                entropy_history.push(merged.entropy);
                deficit_history.push(merged.deficit);
                merged_logits_history.push(merged.merged_logits.clone());

                // Track COLTRANE violations
                if let Some(fsm) = &self.coltrane_fsm {
                    let mask = fsm.compute_valid_token_mask(&merged.merged_logits);
                    let violation_rate =
                        mask.iter().filter(|&&v| !v).count() as f32 / mask.len() as f32;
                    violation_history.push(violation_rate);
                }

                // Sample from merged distribution
                let token_idx = sample_categorical(&merged.merged_logits)?;
                result_tokens.push(token_idx as u32);
                token_idx
            };

            // Forward the selected token through the pipeline. `forward_one`'s Result
            // error type becomes napi::Error under `--features napi` (the bindgen
            // prelude aliases `Result`), so normalize to the String error this fn uses.
            self.pipeline
                .forward_one(token, pos, false)
                .map_err(|e| e.to_string())?;
            self.pipeline.pos += 1;
        }

        Ok(MOADecodingResult {
            tokens: result_tokens,
            merged_logits_history,
            violation_history,
            entropy_history,
            deficit_history,
        })
    }

    /// Decode next token using MOA scheduling.
    fn decode_next_token_moa(&mut self, _pos: usize) -> Result<MOAMergedResult, String> {
        // Get base logits from pipeline (stored in self.pipeline.logits after forward_one)
        let base_logits = self.pipeline.get_logits().to_vec();

        // FORK: Create k temperature-scaled distributions
        let agents_logits = self.fork_temperature_ensemble(&base_logits)?;

        // RACE: Filter non-finite logits
        let filtered = filter_finite_agents(&agents_logits, None);
        if filtered.valid.is_empty() {
            return Err("All agents produced non-finite logits".to_string());
        }

        // FOLD: Deficit-weighted merge
        let vocab_size = self.pipeline.get_config().vocab_size;
        let mut merged = deficit_weighted_merge(
            &filtered.valid,
            vocab_size,
            &self.config.merge_strategy,
            false,
        );

        // COLTRANE: Apply topological masking (mask computed in a scoped borrow
        // so `apply_coltrane_mask` can take `&mut self` without overlapping `fsm`).
        let coltrane_mask = if let Some(fsm) = &mut self.coltrane_fsm {
            Some(fsm.compute_valid_token_mask(&merged.merged_logits))
        } else {
            None
        };
        if let Some(mask) = coltrane_mask {
            merged = self.apply_coltrane_mask(merged, mask)?;
            if let Some(fsm) = &mut self.coltrane_fsm {
                fsm.advance(0);
            }
        }

        // INTERFERE: Update temperature for next step
        if let Some(state) = &mut self.interfere_state {
            interfere(
                state,
                merged.deficit as f32,
                merged.entropy,
                -1, // No token selected yet
                self.config.interfere_sensitivity,
            );
        }

        Ok(merged)
    }

    /// FORK: Create k temperature-scaled agent logits from base logits.
    fn fork_temperature_ensemble(&self, base_logits: &[f32]) -> Result<Vec<Vec<f32>>, String> {
        let vocab_size = self.pipeline.get_config().vocab_size;
        let mut agents_logits = Vec::with_capacity(self.agents.len());

        for agent in &self.agents {
            let scaled = apply_temperature(&base_logits[..vocab_size], agent.temperature);
            agents_logits.push(scaled);
        }

        Ok(agents_logits)
    }

    /// Apply COLTRANE masking to merged logits.
    fn apply_coltrane_mask(
        &self,
        mut merged: MOAMergedResult,
        mask: Vec<bool>,
    ) -> Result<MOAMergedResult, String> {
        const LOGIT_FLOOR: f32 = -1e9;

        for (i, &valid) in mask.iter().enumerate() {
            if !valid && i < merged.merged_logits.len() {
                merged.merged_logits[i] = LOGIT_FLOOR;
            }
        }

        // Recalculate entropy with masked logits
        merged.entropy = stable_softmax_entropy(&merged.merged_logits);

        Ok(merged)
    }
}

/// Apply temperature scaling to logits.
/// Higher temperature → broader distribution
/// Lower temperature → sharper distribution
fn apply_temperature(logits: &[f32], temperature: f32) -> Vec<f32> {
    if (temperature - 1.0).abs() < 1e-6 {
        // Skip scaling if temperature is 1.0
        return logits.to_vec();
    }

    logits.iter().map(|&l| l / temperature).collect()
}

/// Sample token from categorical distribution (logits).
/// Uses max-stable softmax for numerical stability.
fn sample_categorical(logits: &[f32]) -> Result<usize, String> {
    if logits.is_empty() {
        return Err("Empty logits".to_string());
    }

    // Find max for numerical stability
    let max_logit = logits
        .iter()
        .filter(|&&l| l.is_finite())
        .cloned()
        .fold(f32::NEG_INFINITY, f32::max);

    if !max_logit.is_finite() {
        return Err("All logits are non-finite".to_string());
    }

    // Compute exp and softmax
    let mut sum_exp = 0.0;
    let mut probs = vec![0.0; logits.len()];
    for (i, &l) in logits.iter().enumerate() {
        let val = if l.is_finite() { l } else { 0.0 };
        probs[i] = (val - max_logit).exp();
        sum_exp += probs[i];
    }

    if sum_exp <= 0.0 {
        return Err("Invalid softmax sum".to_string());
    }

    // Normalize to probability distribution
    for p in &mut probs {
        *p /= sum_exp;
    }

    // Sample using inverse CDF
    let mut rng = fastrand::Rng::new();
    let u = rng.f32();
    let mut cumsum = 0.0;

    for (i, &p) in probs.iter().enumerate() {
        cumsum += p;
        if u <= cumsum {
            return Ok(i);
        }
    }

    // Fallback: argmax
    let mut max_prob = 0.0;
    let mut max_idx = 0;
    for (i, &p) in probs.iter().enumerate() {
        if p > max_prob {
            max_prob = p;
            max_idx = i;
        }
    }

    Ok(max_idx)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_apply_temperature() {
        let logits = vec![1.0, 2.0, 3.0, 0.5];

        let scaled_identity = apply_temperature(&logits, 1.0);
        let scaled_half = apply_temperature(&logits, 0.5);

        // Temperature 1.0 should return unchanged logits
        assert_eq!(scaled_identity.len(), logits.len());

        // Temperature 0.5 should scale logits (divide by 0.5 = multiply by 2)
        assert_eq!(scaled_half.len(), logits.len());
        assert!((scaled_half[0] - 2.0).abs() < 0.01);
        assert!((scaled_half[1] - 4.0).abs() < 0.01);
    }

    #[test]
    fn test_sample_categorical() {
        // Logits with one clear max
        let logits = vec![10.0, 0.0, 0.0];

        let samples = (0..100)
            .filter_map(|_| sample_categorical(&logits).ok())
            .collect::<Vec<_>>();

        // Most samples should be token 0 (highest logit)
        let zeros = samples.iter().filter(|&&s| s == 0).count();
        assert!(zeros > 50); // Should be heavily biased toward token 0
    }

    #[test]
    fn test_sample_uniform() {
        // Uniform logits
        let logits = vec![0.0, 0.0, 0.0];

        let samples = (0..300)
            .filter_map(|_| sample_categorical(&logits).ok())
            .collect::<Vec<_>>();

        // Should see roughly equal distribution
        let mut counts = [0; 3];
        for &s in &samples {
            if s < 3 {
                counts[s] += 1;
            }
        }

        // Each should have ~100 samples (allowing 20% variance)
        for count in &counts {
            assert!(*count > 60 && *count < 140);
        }
    }
}
